import jwt

def validate_jwt(jwt_token):
    try:
        decoded_data = jwt.decode(
            jwt_token,
            options={"verify_expiration": False},  # Ignore expiration check for validation purposes only
            algorithms=["RS256"] if jwt.RS256 in [jwt.algorithms[i] for i in range(len(jwt.algorithms))] else 'HS256'
        )

        if decoded_data['aud'] == ['your_audience_here']:  # Replace with your audience
            return True, decoded_data.get('exp', False) != 0  # Return bool and exp if not zero

        return False, None
    except jwt.ExpiredSignatureError:
        return False, None  # If signature has expired (not strictly expiration but rather invalid)
    except jwt.InvalidTokenError:
        return False, None  # Any other token validation errors

