import json
import boto3

def s3_metadata_to_json(bucket_name):
    s3 = boto3.client('s3')
    metadata = {
        'Bucket': bucket_name,
        'CreatedDate': None,
        'LastModifiedDate': None,
        'Metadata': {},
        'Owner': {}
    }

    try:
        response = s3.head_bucket(Bucket=bucket_name)
        metadata['CreatedDate'] = response['ResponseMetadata']['HTTPHeaders']['Date']
        metadata['LastModifiedDate'] = response['ResponseMetadata']['HTTPHeaders']['Last-Modified']
        for key, value in response['ResponseMetadata']['HTTPHeaders'].items():
            if not key.startswith('Date'):
                metadata['Metadata'][key] = value
        owner = s3.get_bucket(Bucket=bucket_name)['Owner']
        metadata['Owner'] = {
            'ID': owner['ID'],
            'Email': owner['EmailAddress']
        }
    except Exception as e:
        print(e)

    return json.dumps(metadata, indent=4)

# Usage:
print(s3_metadata_to_json('your-bucket-name'))

