import json

def extract_event_details(event):
    event_type = event['eventType']
    source_arn = event.get('sourceArn')
    event_id = event.get('eventId')

    return {
        'event_type': event_type,
        'source_arn': source_arn,
        'event_id': event_id
    }

def parse_event(event):
    parsed_event = {}
    if isinstance(event, str):  # JSON string
        event_dict = json.loads(event)
    elif isinstance(event, dict):
        event_dict = event
    else:
        return None

    if 'detail' in event_dict and 'eventType' in event_dict['detail']:
        return extract_event_details(event_dict['detail'])
    elif 'sourceArn' in event_dict and 'eventId' in event_dict:
        return {
            'event_type': '',
            'source_arn': event_dict['sourceArn'],
            'event_id': event_dict['eventId']
        }
    else:
        return None

