import json

def validate_iam_policy(policy):
    required_permissions = ['s3:GetObject', 's3:PutObject', 's3:DeleteObject']
    if 'Version' not in policy:
        return False, f"IAM policy version not found"
    if 'Statement' not in policy:
        return False, "IAM policy statement not found"

    for item in policy['Statement']:
        if 'Sid' in item and 'Effect' in item and 'Action' in item:
            action = item['Action']
            if any(permission in action for permission in required_permissions):
                return True, "Policy contains valid permissions"
            else:
                return False, f"Missing required permission: {action}"
    return False, "No valid permission found"

# Test the function
policy = '''
{
  "Version": "2012-10-17",
  "Statement": [
